templates.prompt_zh:
使用結構化 JSON 渲染超逼真的黑板動漫手繪紀錄：

{
  "intent": "對特定黑板藝術作品進行寫實的影像記錄，該作品包含單個動漫角色，完美捕捉教室環境中粉筆媒介的短暫易逝特性。",
  "frame": {
    "aspect_ratio": "4:3",
    "composition": "中景構圖，聚焦於黑板壁畫中心。前景包含講桌以提供比例感，單一角色的手繪作品佔據整個背景空間。",
    "style_mode": "紀實真實主義，聚焦材質紋理，環境自然感"
  },
  "subject": {
    "primary_subject": "在標準綠色教室黑板上，一幅大比例、極致精細的 {動漫角色} 粉筆手繪。",
    "visual_details": "手繪描繪了角色的經典姿態，位於黑板中心。她長長的直髮採用密集的黑色粉筆和白色高光繪製以體現光澤。神情高傲冷艷，雙眼刻畫極其細緻。雙手於身前做出經典的招式動作。身上穿著細節豐富的 {衣物顏色}，佩戴精緻耳環，均使用色彩斑斕的彩色粉筆細膩繪製。",
    "medium_texture": "影象完美保留了粉筆朦朧、無光的霧面質感。清晰可見的排線與交叉排線筆觸在衣服和頭髮上創造出精美的陰影。綠色板面上的塗抹痕跡清晰呈現出由手工暈染顏色的動態過程。",
    "surrounding_elements": "在角色右側，用乾淨的白色粉筆豎寫著日文字型「{黑板文字}」。"
  },
  "environment": {
    "location": "一間標準的日式學校教室。",
    "foreground_elements": "前景是一張木製的教師講臺。桌面上散落著一盒黃色的彩色粉筆、幾根散落的紅、白、藍色短粉筆，以及一個落滿粉筆灰的黑色毛氈黑板擦。",
    "background_elements": "綠色黑板橫跨整個畫面，邊緣裝有金屬粉筆槽，槽內積滿了薄薄的粉筆灰。上方牆面是簡約的灰白色石膏牆，掛著一個小型廣播喇叭。",
    "atmosphere": "安靜肅穆的教室氣氛，空氣中瀰漫著靜謐感，暗示教室目前空無一人。"
  },
  "lighting": {
    "type": "漫射的教室環境光。",
    "quality": "由頭頂的日光燈與左側窗戶灑入的自然光混合而成的柔和、無方向性光線。光線極其均勻，防止了黑板板面的反光，同時完美襯托出粉筆的顆粒質感。",
    "color_temperature": "中性白光，約 5000K，確保彩色粉筆在深綠色黑板上的色彩還原極其準確。",
    "direction": "頭頂上方且微前方偏斜。"
  },
  "camera": {
    "sensor_format": "35mm 全畫幅數位感光元件。",
    "lens": "35mm 定焦鏡頭。",
    "aperture": "f/5.6",
    "depth_of_field": "中等景深，使黑板上的畫作保持絕對銳利的焦點，同時讓前景講桌上的物品略微虛化，增強層次。",
    "shutter_speed": "1/60s",
    "iso": "400",
    "camera_position": "與視線齊平的站立視角，退後至剛好框下整幅板畫與講桌的距離。"
  },
  "negative": {
    "content": "多個角色，數碼插畫疊加，向量圖形，紙張紋理，油畫，雜亂構圖，極端低角度，魚眼鏡頭。",
    "style": "拒絕過度飽和，無柔焦濾鏡，無重度暗角。"
  }
}

